                            fontSize = 13.sp
                        )
                    }
                }
            }

            Spacer(modifier = Modifier.height(16.dp))

            // Task List
            uiState.displayedTasks.forEach { task ->
                TaskCard(task)
                Spacer(modifier = Modifier.height(12.dp))
            }

            Spacer(modifier = Modifier.height(60.dp)) // padding for FAB
        }
    }
}

@Composable
fun TaskCard(task: TaskItemUi) {
    val isCompleted = task.status == "COMPLETED"
    val chipBgColor = if (isCompleted) Color(0xFFF0FDF4) else Color(0xFFEFF6FF)
    val chipTextColor = if (isCompleted) Color(0xFF16A34A) else Color(0xFF1D4ED8)
    val titleColor = if (isCompleted) Color(0xFF94A3B8) else Color(0xFF0F172A)
    val descColor = if (isCompleted) Color(0xFF94A3B8) else Color(0xFF475569)

    Card(
        colors = CardDefaults.cardColors(containerColor = Color.White),
        shape = RoundedCornerShape(12.dp),
        elevation = CardDefaults.cardElevation(defaultElevation = 0.dp),
        modifier = Modifier.fillMaxWidth()
    ) {
        Row(modifier = Modifier.height(IntrinsicSize.Min)) {
            // Left color bar
            if (!isCompleted) {
                val barColor = if (task.isDueSoon) Color(0xFFDC2626) else Color(0xFFB45309)
                Box(
                    modifier = Modifier
                        .fillMaxHeight()
                        .width(4.dp)
                        .padding(vertical = 16.dp)
                        .background(barColor, RoundedCornerShape(topEnd = 4.dp, bottomEnd = 4.dp))
                )
            } else {
                Spacer(modifier = Modifier.width(4.dp))
            }

            Column(modifier = Modifier.padding(16.dp).weight(1f)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.Top
                ) {
                    Text(
                        text = task.title,
                        color = titleColor,
                        fontSize = 16.sp,
                        fontWeight = FontWeight.Bold,
                        textDecoration = if (isCompleted) TextDecoration.LineThrough else null,
                        modifier = Modifier.weight(1f)
                    )
                    Spacer(modifier = Modifier.width(8.dp))
                    Surface(
                        color = chipBgColor,
                        shape = RoundedCornerShape(4.dp)
                    ) {
                        Text(
                            text = task.status,
                            color = chipTextColor,
                            fontSize = 9.sp,
                            fontWeight = FontWeight.Black,
                            modifier = Modifier.padding(horizontal = 6.dp, vertical = 3.dp),
                            letterSpacing = 0.5.sp
                        )
                    }
                }
                Spacer(modifier = Modifier.height(8.dp))
                Text(
                    text = task.description,
                    color = descColor,
                    fontSize = 13.sp,
                    lineHeight = 18.sp,
                    textDecoration = if (isCompleted) TextDecoration.LineThrough else null
                )
                Spacer(modifier = Modifier.height(16.dp))
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.End,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    if (task.dueText != null && !isCompleted) {
                        if (task.isDueSoon) {
                            Text(
                                "!",
                                color = Color(0xFFDC2626),
                                fontWeight = FontWeight.Bold,
                                fontSize = 14.sp
                            )
                            Spacer(modifier = Modifier.width(4.dp))
                        }
                        Text(
                            text = task.dueText ?: "",
                            color = if (task.isDueSoon) Color(0xFFDC2626) else Color(0xFFB45309),
                            fontSize = 10.sp,
                            fontWeight = FontWeight.Black,
                            letterSpacing = 0.5.sp
                        )
                        Spacer(modifier = Modifier.width(16.dp))
                    }

                    if (isCompleted) {
                        Icon(
                            imageVector = Icons.Outlined.CheckCircle,
                            contentDescription = null,
                            tint = Color(0xFF94A3B8),
                            modifier = Modifier.size(14.dp)
                        )
                    } else {
                        Icon(
                            imageVector = Icons.Outlined.CalendarToday,
                            contentDescription = null,
                            tint = Color(0xFF64748B),
                            modifier = Modifier.size(14.dp)
                        )
                    }
                    Spacer(modifier = Modifier.width(4.dp))
                    Text(
                        text = task.dateText,
                        color = if (isCompleted) Color(0xFF94A3B8) else Color(0xFF64748B),
                        fontSize = 12.sp,
                        fontWeight = FontWeight.SemiBold
                    )
                }
            }
        }
    }
}

package com.example.minorapp.data.auth

import com.example.minorapp.domain.model.UserRole
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import org.json.JSONObject
import java.io.IOException
import java.net.HttpURLConnection
import java.net.URL

sealed class AuthResult {
    data class Success(
        val accessToken: String,
        val refreshToken: String,
        val userId: Long,
        val email: String,
        val role: UserRole,
        val username: String?,
        val branch: String?,
        val batch: String?
    ) : AuthResult()

    data class Failure(val message: String) : AuthResult()
}

class AuthRepository(private val baseUrl: String) {
    suspend fun authenticate(
        email: String,
        password: String
    ): AuthResult = withContext(Dispatchers.IO) {
        var connection: HttpURLConnection? = null

        try {
            val normalizedBaseUrl = if (baseUrl.endsWith("/")) baseUrl else "$baseUrl/"
            val loginUrl = URL("${normalizedBaseUrl}${AuthConfig.AUTH_LOGIN_PATH}")

            connection = (loginUrl.openConnection() as HttpURLConnection).apply {
                requestMethod = "POST"
                connectTimeout = 10_000
                readTimeout = 10_000
                doOutput = true
                setRequestProperty("Content-Type", "application/json")
                setRequestProperty("Accept", "application/json")
            }

            val payload = JSONObject()
                .put("email", email)
                .put("password", password)
                .toString()

            connection.outputStream.use { output ->
                output.write(payload.toByteArray(Charsets.UTF_8))
                output.flush()
            }

            when (val statusCode = connection.responseCode) {
                in 200..299 -> parseSuccessResponse(connection)
                401 -> AuthResult.Failure("Invalid email or security key.")
                else -> AuthResult.Failure("Authentication failed ($statusCode).")
            }
        } catch (_: IOException) {
            AuthResult.Failure("Unable to reach server. Check connection and try again.")
        } catch (_: Exception) {
            AuthResult.Failure("Authentication service is currently unavailable.")
        } finally {
            connection?.disconnect()
        }
    }

    private fun parseSuccessResponse(connection: HttpURLConnection): AuthResult {
        val responseBody = connection.inputStream.bufferedReader().use { it.readText() }
        val root = JSONObject(responseBody)

        val status = root.optString("status")
        if (status != AuthConfig.SUCCESS_STATUS) {
            val message = root.optString("message").ifBlank { "Authentication failed." }
            return AuthResult.Failure(message)
        }

        val data = root.optJSONObject("data") ?: return AuthResult.Failure("Malformed auth response.")
        val accessToken = data.optString("accessToken")
        val refreshToken = data.optString("refreshToken")
        val user = data.optJSONObject("user") ?: return AuthResult.Failure("Malformed auth response.")

        val userId = user.optLong("id", -1L)
        val userEmail = user.optString("email")
        val roleRaw = user.optString("role")
        val role = roleRaw.toUserRoleOrNull()
        val username = user.optFirstNonBlank("username", "name", "fullName", "displayName")
        val branch = user.optFirstNonBlank("branch", "department", "program", "major")
        val batch = user.optFirstNonBlank("batch", "classOf", "cohort", "year", "classSection")

        if (accessToken.isBlank() || refreshToken.isBlank() || userId <= 0L || userEmail.isBlank() || role == null) {
            return AuthResult.Failure("Malformed auth response.")
        }

        return AuthResult.Success(
            accessToken = accessToken,
            refreshToken = refreshToken,
            userId = userId,
            email = userEmail,
            role = role,
            username = username,
            branch = branch,
            batch = batch
        )
    }

    private fun String.toUserRoleOrNull(): UserRole? {
        return runCatching { UserRole.valueOf(this.uppercase()) }.getOrNull()
    }

    private fun JSONObject.optFirstNonBlank(vararg keys: String): String? {
        for (key in keys) {
            val value = optString(key).trim()
            if (value.isNotBlank()) return value
        }
        return null
    }
}

package com.example.minorapp.data.auth

import com.example.minorapp.domain.model.UserRole
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import org.json.JSONObject
import java.io.IOException
import java.net.HttpURLConnection
import java.net.URL

sealed class AuthResult {
    data class Success(
        val accessToken: String,
        val refreshToken: String,
        val userId: Long,
        val email: String,
        val role: UserRole,
        val username: String?,
        val branch: String?,
        val batch: String?
    ) : AuthResult()

    data class Failure(val message: String) : AuthResult()
}

class AuthRepository(private val baseUrl: String) {
    suspend fun authenticate(
        email: String,
        password: String,
        selectedRole: UserRole
    ): AuthResult = withContext(Dispatchers.IO) {
        var connection: HttpURLConnection? = null

        try {
            val normalizedBaseUrl = if (baseUrl.endsWith("/")) baseUrl else "$baseUrl/"
            val loginUrl = URL("${normalizedBaseUrl}${AuthConfig.AUTH_LOGIN_PATH}")

            connection = (loginUrl.openConnection() as HttpURLConnection).apply {
                requestMethod = "POST"
                connectTimeout = 10_000
                readTimeout = 10_000
                doOutput = true
                setRequestProperty("Content-Type", "application/json")
                setRequestProperty("Accept", "application/json")
            }

            val payload = JSONObject()
                .put("email", email)
                .put("password", password)
                .put("role", selectedRole.name)
                .toString()

            connection.outputStream.use { output ->
                output.write(payload.toByteArray(Charsets.UTF_8))
                output.flush()
            }

            when (val statusCode = connection.responseCode) {
                in 200..299 -> parseSuccessResponse(connection)
                401 -> AuthResult.Failure("Invalid email or security key.")
                403 -> AuthResult.Failure(readErrorMessage(connection, "Selected role does not match this account."))
                400 -> AuthResult.Failure(readErrorMessage(connection, "Invalid login request."))
                else -> AuthResult.Failure("Authentication failed ($statusCode).")
            }
        } catch (_: IOException) {
            AuthResult.Failure("Unable to reach server. Check connection and try again.")
        } catch (_: Exception) {
            AuthResult.Failure("Authentication service is currently unavailable.")
        } finally {
            connection?.disconnect()
        }
    }

    private fun readErrorMessage(connection: HttpURLConnection, fallback: String): String {
        return runCatching {
            val raw = connection.errorStream?.bufferedReader()?.use { it.readText() } ?: return fallback
            val root = JSONObject(raw)
            root.optString("message").ifBlank { fallback }
        }.getOrElse { fallback }
    }

    private fun parseSuccessResponse(connection: HttpURLConnection): AuthResult {
        val responseBody = connection.inputStream.bufferedReader().use { it.readText() }
        val root = JSONObject(responseBody)

        val status = root.optString("status")
        if (status != AuthConfig.SUCCESS_STATUS) {
            val message = root.optString("message").ifBlank { "Authentication failed." }
            return AuthResult.Failure(message)
        }

        val data = root.optJSONObject("data") ?: return AuthResult.Failure("Malformed auth response.")
        val accessToken = data.optString("accessToken")
        val refreshToken = data.optString("refreshToken")
        val user = data.optJSONObject("user") ?: return AuthResult.Failure("Malformed auth response.")

        val userId = user.optLong("id", -1L)
        val userEmail = user.optString("email")
        val roleRaw = user.optString("role")
        val role = roleRaw.toUserRoleOrNull()
        val username = user.optFirstNonBlank("username", "name", "fullName", "displayName")
        val branch = user.optFirstNonBlank("branch", "department", "program", "major")
        val batch = user.optFirstNonBlank("batch", "classOf", "cohort", "year", "classSection")

        if (accessToken.isBlank() || refreshToken.isBlank() || userId <= 0L || userEmail.isBlank() || role == null) {
            return AuthResult.Failure("Malformed auth response.")
        }

        return AuthResult.Success(
            accessToken = accessToken,
            refreshToken = refreshToken,
            userId = userId,
            email = userEmail,
            role = role,
            username = username,
            branch = branch,
            batch = batch
        )
    }

    private fun String.toUserRoleOrNull(): UserRole? {
        return runCatching { UserRole.valueOf(this.uppercase()) }.getOrNull()
    }

    private fun JSONObject.optFirstNonBlank(vararg keys: String): String? {
        for (key in keys) {
            val value = optString(key).trim()
            if (value.isNotBlank()) return value
        }
        return null
    }
}

package com.example.minorapp.presentation.screen.login

import android.util.Patterns
import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.setValue
import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.example.minorapp.data.auth.AuthRepository
import com.example.minorapp.data.auth.AuthResult
import com.example.minorapp.domain.model.UserRole
import kotlinx.coroutines.Job
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch

data class LoginUiState(
    val selectedRole: UserRole = UserRole.STUDENT,
    val email: String = "",
    val password: String = "",
    val emailError: String? = null,
    val errorMessage: String? = null,
    val authStatusMessage: String? = null,
    val isAuthenticating: Boolean = false,
    val credentialsVerified: Boolean = false,
    val authenticatedRole: UserRole? = null,
    val accessToken: String? = null,
    val refreshToken: String? = null,
    val username: String? = null,
    val branch: String? = null,
    val batch: String? = null,
    val rememberFor30Days: Boolean = false
)

class LoginViewModel(
    private val authRepository: AuthRepository
) : ViewModel() {
    var uiState by mutableStateOf(LoginUiState())
        private set

    private var realtimeAuthJob: Job? = null

    companion object {
        fun factory(authRepository: AuthRepository): ViewModelProvider.Factory {
            return object : ViewModelProvider.Factory {
                @Suppress("UNCHECKED_CAST")
                override fun <T : ViewModel> create(modelClass: Class<T>): T {
                    return LoginViewModel(authRepository) as T
                }
            }
        }
    }

    fun onRoleSelected(role: UserRole) {
        uiState = uiState.copy(
            selectedRole = role,
            credentialsVerified = false,
            authenticatedRole = null,
            accessToken = null,
            refreshToken = null,
            username = null,
            branch = null,
            batch = null,
            authStatusMessage = null,
            errorMessage = null
        )
        scheduleRealtimeAuthentication()
    }

    fun onEmailChanged(email: String) {
        val trimmedEmail = email.trim()
        uiState = uiState.copy(
            email = trimmedEmail,
            emailError = validateEmail(trimmedEmail),
            errorMessage = null,
            authStatusMessage = null,
            credentialsVerified = false,
            authenticatedRole = null,
            accessToken = null,
            refreshToken = null,
            username = null,
            branch = null,
            batch = null
        )
        scheduleRealtimeAuthentication()
    }

    fun onPasswordChanged(password: String) {
        uiState = uiState.copy(
            password = password,
            errorMessage = null,
            authStatusMessage = null,
            credentialsVerified = false,
            authenticatedRole = null,
            accessToken = null,
            refreshToken = null,
            username = null,
            branch = null,
            batch = null
        )
        scheduleRealtimeAuthentication()
    }

    fun onRememberFor30DaysChanged(rememberFor30Days: Boolean) {
        uiState = uiState.copy(rememberFor30Days = rememberFor30Days)
    }


    fun onLoginRequested(onValidRequest: (LoginUiState) -> Unit) {
        if (uiState.email.isBlank() || uiState.password.isBlank()) {
            uiState = uiState.copy(
                errorMessage = "Please enter email and security key.",
                authStatusMessage = null
            )
            return
        }

        if (uiState.emailError != null) {
            uiState = uiState.copy(
                errorMessage = uiState.emailError,
                authStatusMessage = null
            )
            return
        }

        viewModelScope.launch {
            val authenticated = authenticate(showSuccessMessage = false)
            if (authenticated) {
                onValidRequest(uiState)
            }
        }
    }

    private fun scheduleRealtimeAuthentication() {
        realtimeAuthJob?.cancel()

        if (!isReadyForAuth()) return

        realtimeAuthJob = viewModelScope.launch {
            delay(450)
            authenticate(showSuccessMessage = true)
        }
    }

    private fun isReadyForAuth(): Boolean {
        return uiState.email.isNotBlank() &&
            uiState.password.isNotBlank() &&
            uiState.emailError == null
    }

    private suspend fun authenticate(showSuccessMessage: Boolean): Boolean {
        uiState = uiState.copy(
            isAuthenticating = true,
            errorMessage = null,
            authStatusMessage = "Authenticating..."
        )

        return when (
            val result = authRepository.authenticate(
                email = uiState.email,
                password = uiState.password
            )
        ) {
            is AuthResult.Success -> {
                uiState = uiState.copy(
                    isAuthenticating = false,
                    credentialsVerified = true,
                    authenticatedRole = result.role,
                    accessToken = result.accessToken,
                    refreshToken = result.refreshToken,
                    username = result.username,
                    branch = result.branch,
                    batch = result.batch,
                    errorMessage = null,
                    authStatusMessage = if (showSuccessMessage) "Credentials verified." else null
                )
                true
            }

            is AuthResult.Failure -> {
                uiState = uiState.copy(
                    isAuthenticating = false,
                    credentialsVerified = false,
                    authStatusMessage = null,
                    errorMessage = result.message,
                    username = null,
                    branch = null,
                    batch = null
                )
                false
            }
        }
    }

    private fun validateEmail(email: String): String? {
        if (email.isBlank()) return null
        return if (Patterns.EMAIL_ADDRESS.matcher(email).matches()) {
            null
        } else {
            "Please enter a valid institutional email address."
        }
    }
}

package com.example.minorapp.presentation.screen.login

import android.util.Patterns
import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
